# ---------------------------------------------------------------------------- #
## 1.1 Sunrise Time ----
# Here we will calculate the sunrise time for every municipality in Brazil in the
# exams days.
# ---------------------------------------------------------------------------- #

# 1. Create a point inside each municipality polygon
#    Use a projected CRS first to avoid geometry issues.
mun_sun_sf <- mun_hv %>%
  st_transform(5880) %>%          # SIRGAS 2000 / Brazil Polyconic
  st_point_on_surface() %>%
  st_transform(4326)              # Convert back to longitude/latitude

# 2. Extract coordinates
coords <- st_coordinates(mun_sun_sf)

# 3. Build a plain data frame with municipality attributes + coordinates
mun_sun <- mun_sun_sf %>%
  st_drop_geometry() %>%
  bind_cols(
    tibble(
      lon = coords[, 1],
      lat = coords[, 2]
    )
  ) %>%
  select(co_municipio, uf, hv, seg, lat, lon)

# 4. Create the date grid
datas <- tibble(
  date = as.Date(c(
    "2013-10-26",  # ENEM 2013 - Day 1
    "2013-10-27",  # ENEM 2013 - Day 2
    "2014-11-08",  # ENEM 2014 - Day 1
    "2014-11-09",  # ENEM 2014 - Day 2
    "2015-10-24",  # ENEM 2015 - Day 1
    "2015-10-25",  # ENEM 2015 - Day 2
    "2016-11-05",  # ENEM 2016 - Day 1
    "2016-11-06",  # ENEM 2016 - Day 2
    "2017-11-05",  # ENEM 2017 - Day 1
    "2017-11-12",  # ENEM 2017 - Day 2
    "2018-11-04",  # ENEM 2018 - Day 1
    "2018-11-11",  # ENEM 2018 - Day 2
    "2019-11-03",  # ENEM 2019 - Day 1
    "2019-11-10"   # ENEM 2019 - Day 2
  ))
)
# 5. Expand municipality x date
mun_sun_panel <- crossing(mun_sun, datas) %>%
  mutate(id = row_number())

# 6. Calculate sunrise time
sunrise_panel <- suncalc::getSunlightTimes(
  data = mun_sun_panel,
  keep = "sunrise",
  tz   = "America/Sao_Paulo"
) %>%
  as_tibble() %>%
  mutate(
    id = row_number(),
    sunrise_hms = format(sunrise, "%H:%M:%S"),
    sunrise_min = hour(sunrise) * 60 + minute(sunrise) + second(sunrise) / 60
  ) %>%
  left_join(
    mun_sun_panel %>% select(id, co_municipio, uf, hv, seg),
    by = "id"
  ) %>%
  select(co_municipio, uf, hv, date, lat, lon, sunrise, sunrise_hms, sunrise_min)

# 7. Sunrise-time to exam.
sunrise_panel <- sunrise_panel %>%
  mutate(
    exam_start = ymd_hms(
      paste(date, "13:00:00"),
      tz = "America/Sao_Paulo"
    ),
    
    sunrise_to_exam =
      as.numeric(
        difftime(exam_start, sunrise, units = "mins")
      )
  )


# 8. Final organization

sunrise_wide <- sunrise_panel %>%
  mutate(
    ano = year(date)
  ) %>%
  group_by(co_municipio, ano) %>%
  arrange(date, .by_group = TRUE) %>%
  mutate(
    exam_day = paste0("day", row_number())
  ) %>%
  ungroup() %>%
  select(co_municipio, ano, exam_day, sunrise_to_exam) %>%
  pivot_wider(
    names_from = exam_day,
    values_from = sunrise_to_exam,
    names_prefix = "time_to_enem_"
  ) %>% 
  group_by(co_municipio, ano) %>% 
  # For both days
  mutate(time_to_enem_both =
           round( (time_to_enem_day1 + time_to_enem_day2) / 2,
                  digits = 4)) %>% 
  ungroup()

# Salving the base
saveRDS(sunrise_wide, file.path(revision_path, "sunrise_panel.RDS"))

rm(sunrise_wide, sunrise_panel, mun_sun_panel, mun_sun_sf, mun_sun, datas, coords)

# ---------------------------------------------------------------------------- #
# 2. GDP per capita ----
# ---------------------------------------------------------------------------- #

# Builds municipality-year GDP per capita using IBGE GDP and population data.

# ---------------------------------------------------------------------------- #
# 1. Load GDP (raw data)
# ---------------------------------------------------------------------------- #

gdp <- readxl::read_xlsx(
  path = file.path(raw_data_path, "gdp_pop", "tabela5938.xlsx"),
  range = "A3:D61273"
) %>%
  rename(
    codmun = 1,
    nomemun = 2,
    year = 3,
    gdp = 4
  ) %>%
  select(-nomemun) %>%
  mutate(year = as.integer(year))

# Fill municipality codes (IBGE format issue: codes appear once per block)
for (i in 0:10) {
  j <- i + 2009
  gdp <- gdp %>%
    mutate(
      codmun = ifelse(year == j & is.na(codmun),
                      lag(codmun, n = i),
                      codmun)
    )
}

# ---------------------------------------------------------------------------- #
# 2. Load population (raw data)
# ---------------------------------------------------------------------------- #

pop <- readxl::read_xlsx(
  path = file.path(raw_data_path, "gdp_pop", "tabela6579.xlsx"),
  range = "A3:D55703"
) %>%
  rename(
    codmun = 1,
    nomemun = 2,
    year = 3,
    pop = 4
  ) %>%
  mutate(year = as.integer(year)) %>%
  select(-nomemun)

# Same filling logic for municipality codes
for (i in 0:9) {
  j <- ifelse(i == 0, i + 2009, i + 2010)
  pop <- pop %>%
    mutate(
      codmun = ifelse(year == j & is.na(codmun),
                      lag(codmun, n = i),
                      codmun)
    )
}

# ---------------------------------------------------------------------------- #
# 3. Add detailed 2010 population
# ---------------------------------------------------------------------------- #

pop2010 <- readxl::read_xlsx(
  path = file.path(raw_data_path, "gdp_pop", "tabela1378.xlsx"),
  range = "A5:F5570"
) %>%
  rename(
    codmun = 1,
    nomemun = 2,
    age = 3,
    condition = 4,
    year = 5,
    pop = 6
  ) %>%
  mutate(year = as.integer(year)) %>%
  select(-nomemun, -age, -condition)

pop <- pop %>%
  bind_rows(pop2010) %>%
  mutate(year = as.integer(year))

rm(pop2010)

# ---------------------------------------------------------------------------- #
# 4. Compute GDP per capita
# ---------------------------------------------------------------------------- #

gdp <- gdp %>% 
  left_join(pop, by = c("year", "codmun")) %>%
  mutate(
    gdppc = (gdp / pop) * 1000  # IBGE scaling
  ) %>%
  select(-gdp, -pop)

# ---------------------------------------------------------------------------- #
# 5. Save to intermediate data
# ---------------------------------------------------------------------------- #

saveRDS(
  gdp,
  file = file.path(revision_path, "pib.rds")
)

rm(gdp, pop)


