## 3.1 Functions ---------
# ---------------------------------------------------------------------------- #

# Helper functions used to standardize scores, harmonize raw ENEM variables, and
# create filtered score/absence datasets.

#Standardizes the scores
pad <- function(x){
  x = (x - mean(x, na.rm = T)) / 
    sd(x, na.rm = T)
  return(x)
}

# Function to calculate the weighted standard errors, according to formula on:
#https://medium.com/@OttoYu/weighted-mean-and-standard-devation-computation-f1dbacdf49b6



weighted.sd <- function(x,w,na.rm){
  
  # Verifying whether x and w have the same length
  if(length(x) == length(w)){
    
    # removing NA
    if(!missing(na.rm)){
      if(na.rm == T){
        temp <- !is.na(x) & !is.na(w)
        x <- x[temp]
        w <- w[temp]
        rm(temp)
      } 
    }
    
    # Calculating SD
    x = ((w %*% (x - weighted.mean(x, w = w))^2) / (sum(w)))^(1/2)
    
    return(x)
  }
}


#Weighted standardization
# Standardizes scores using weighted means and weighted standard deviations.
wpad <- function(x,w){
  x = (x - weighted.mean(x,w = w, na.rm = T))/as.vector(weighted.sd(x, w = w, na.rm = T))
  return(x)
}


#Data organization
# Receives a raw ENEM file and returns a harmonized version with common column
# names, comparable categories across years, absence flags, and base indicators.
org_data <- function(base,ano,vlist,cnames) {
  
  # Data organization
  # Reorders the raw columns and applies the standardized names defined below.
  base <- base %>% relocate(vlist)
  
  colnames(base) <- cnames
  
  # People in the household ------------------------------------------------------#
  # [English: People within each household]
  # Harmonizes household-size categories because ENEM questionnaire options
  # changed across years.
  
  if (ano == 2009) {
    # Modifications only for 2009
    # [English: 2009 exclusive modifications]
    
    base <- base %>%
      mutate(
        # 2009
        pessoas_dom = case_when(
          pessoas_dom == 'F' ~ 'A',
          # 1 person
          
          pessoas_dom %in% c('A', 'B', 'C') ~ 'B',
          # 2 to 4 people
          
          pessoas_dom %in% c('D', 'E') ~ 'C',
          # 5 or more people
          
          .default = 'D'
        ),
      )
  } else if (ano == 2010) {
    # Modifications only for 2010
    
    base <- base %>%
      mutate(
        # 2010
        pessoas_dom = case_when(
          pessoas_dom == 'E' ~ 'A',
          pessoas_dom == 'A' ~ 'B',
          pessoas_dom %in% c('B', 'C', 'D') ~ 'C',
          .default = 'D'
        )
      )
    
  } else if (ano == 2011) {
    
    # Modifications only for 2011
    base <- base %>%
      mutate(
        pessoas_dom = as.integer(pessoas_dom),
        pessoas_dom = case_when(
          pessoas_dom == 1 ~ 'A',
          pessoas_dom >= 2 & pessoas_dom <= 4 ~ 'B',
          pessoas_dom >= 5 & pessoas_dom <= 20 ~ 'C',
          .default = 'D'
        )
      )
    
  } else if (ano >= 2012) {
    
    # Modifications only for 2012 to 2019
    # base <- base %>%
    #   mutate(
    #     pessoas_dom = case_when(
    #       pessoas_dom == 1 ~ 'A',
    #       pessoas_dom >= 2 & pessoas_dom <= 4 ~ 'B',
    #       pessoas_dom >= 5 & pessoas_dom <= 20 ~ 'C',
    #       .default = 'D'
    #     )
    #   )
  }  
  
  # Household income ----------------------------------------------------------#
  # Harmonizes income categories into comparable bins across ENEM years.
  
  if (ano %in% c(2009,2010)) {
    
    # Modifications only for 2009 and 2010
    base <- base %>%
      mutate(
        # 2009, 2010
        renda_dom = case_when(
          renda_dom == 'H' ~ 'A',
          # None
          renda_dom == 'A' ~ 'B',
          # Up to 1 MW
          renda_dom %in% c('B', 'C', 'D') ~ 'C',
          # >1 to 10 MW
          renda_dom %in% c('E', 'F', 'G') ~ 'D',
          # >10 to 50 MW
          .default = 'E'
        )
      )
  } else if (ano == 2011) {
    
    # Modifications only for 2011
    base <- base %>%
      mutate(
        renda_dom = case_when(
          renda_dom == 'A' ~ 'A',
          renda_dom == 'B' ~ 'B',
          renda_dom %in% c('C', 'D', 'E', 'F', 'G') ~ 'C',
          renda_dom %in% c('H', 'I', 'J', 'K') ~ 'D',
          .default = 'E'
        )
      )
  } else if (ano >= 2012) {
    
    # Modifications from 2012 onward
    base <- base %>%
      mutate(
        renda_dom = case_when(
          renda_dom == 'A' ~ 'A',
          renda_dom == 'B' ~ 'B',
          renda_dom %in% c('C', 'D', 'E', 'F', 'G', 'H', 'I', 'J', 'K', 'L', 'M') ~ 'C',
          renda_dom %in% c('N', 'O', 'P', 'Q') ~ 'D',
          .default = 'E'
        )
      )
  }
  
  # Race ----------------------------------------------------------------------#
  # Harmonizes race/color categories and separates invalid or missing codes.
  
  if(ano == 2009) {
    
    # Modifications only for 2009
    base <- base %>%
      mutate(
        # 2009
        raca = case_when(
          raca %in% c('', '*', '.') ~ 'A',
          # invalid
          raca == 'A' ~ 'B',
          # white
          raca == 'C' ~ 'C',
          # black
          raca == 'B' ~ 'D',
          # brown/mixed
          raca == 'D' ~ 'E',
          # yellow/Asian
          raca == 'E' ~ 'F',
          # indigenous
          .default = 'G'
        )
      )
  } else if (ano %in% c(2010, 2011, 2012, 2013, 2014, 2017, 2018, 2019)) {
    
    # Modifications only for 2010 to 2014 and 2017 to 2019
    base <- base %>%
      mutate(
        # 2010, 2011, 2012, 2013, 2014, 2017, 2018, 2019
        raca = case_when(
          raca == 0 ~ 'A',
          raca == 1 ~ 'B',
          raca == 2 ~ 'C',
          raca == 3 ~ 'D',
          raca == 4 ~ 'E',
          raca == 5 ~ 'F',
          .default = 'G'
        )
        
      )
    
  } else if(ano %in% c(2015,2016)) {
    
    # Modifications only for 2015 and 2016
    base <- base %>%
      mutate(
        
        # 2015, 2016
        raca = case_when(
          raca %in% c(0,6) ~ 'A',
          raca == 1 ~ 'B',
          raca == 2 ~ 'C',
          raca == 3 ~ 'D',
          raca == 4 ~ 'E',
          raca == 5 ~ 'F',
          .default = 'G')
        
      )
    
  }
  
  # Father's education -------------------------------------------------------#
  # Harmonizes father and mother education categories across questionnaires.
  
  if (ano == 2010) {
    
    # Modifications only for 2010
    base <- base %>%
      mutate(
        esc_pai = case_when(
          esc_pai == "H" ~ "A",
          esc_pai == "A" ~ "B",
          esc_pai == "B" ~ "C",
          esc_pai == "C" ~ "D",
          esc_pai == "D" ~ "E",
          esc_pai %in% c("E", "F", "G") ~ "F",
          esc_pai == "I" ~ "G",
          .default = "H"
        ),
        
        esc_mae = case_when(
          esc_mae == "H" ~ "A",
          esc_mae == "A" ~ "B",
          esc_mae == "B" ~ "C",
          esc_mae == "C" ~ "D",
          esc_mae == "D" ~ "E",
          esc_mae %in% c("E", "F", "G") ~ "F",
          esc_mae == "I" ~ "G",
          .default = "H"
        )
      )
  } else if (ano == 2009 | (ano >= 2009 & ano <= 2014)) {
    
    # Modifications only for 2009 and 2011 to 2014
    base <- base %>%
      mutate(
        esc_pai = case_when(
          esc_pai == "A" ~ "A",
          # Did not study
          esc_pai == "B" ~ "B",
          # Elementary school first cycle complete
          esc_pai %in% c("C", "D") ~ "C",
          # Elementary school second cycle complete
          esc_pai %in% c("E", "F") ~ "D",
          # High school complete
          esc_pai == "G" ~ "E",
          # Higher education complete
          esc_pai == "H" ~ "F",
          # Postgraduate
          esc_pai == "I" ~ "G",
          # Does not know
          .default = "H"
          # missing
        ),
        
        esc_mae = case_when(
          esc_mae == "A" ~ "A",
          # Did not study
          esc_mae == "B" ~ "B",
          # Elementary school first cycle complete
          esc_mae %in% c("C", "D") ~ "C",
          # Elementary school second cycle complete
          esc_mae %in% c("E", "F") ~ "D",
          # High school complete
          esc_mae == "G" ~ "E",
          # Higher education complete
          esc_mae == "H" ~ "F",
          # Postgraduate
          esc_mae == "I" ~ "G",
          # Does not know
          .default = "H"
          # missing
        )
        
      )
  } else if (ano >= 2015 & ano <= 2019) {
    
    # Modifications only for 2015 to 2019
    base <- base %>%
      mutate(
        esc_pai = case_when(
          esc_pai %in% c("A", "B") ~ "A",
          esc_pai == "C" ~ "B",
          esc_pai == "D" ~ "C",
          esc_pai == "E" ~ "D",
          esc_pai == "F" ~ "E",
          esc_pai == "G" ~ "F",
          esc_pai == "H" ~ "G",
          .default = "H"
        ),
        esc_mae = case_when(
          esc_mae %in% c("A", "B") ~ "A",
          esc_mae == "C" ~ "B",
          esc_mae == "D" ~ "C",
          esc_mae == "E" ~ "D",
          esc_mae == "F" ~ "E",
          esc_mae == "G" ~ "F",
          esc_mae == "H" ~ "G",
          .default = "H"
        ) 
        
        
        
      )
  } 
  
  # Household assets --------------------------------------------------------#
  # Recodes household assets and access variables into numeric/common indicators.
  
  if(ano < 2015) {
    
    base <- base %>% 
      mutate(
        #Domestic worker
        empr_dom = case_when(
          empr_dom == "D" ~ 0, #No domestic worker
          empr_dom %in% c("A", "B", "C") ~ 1,
          .default        = NA  #With one or more
        ),
        
        #Bathrooms
        n_banheiro = case_when(
          n_banheiro == "D" ~ 0,
          n_banheiro == "A" ~ 1,
          n_banheiro == "B" ~ 2,
          n_banheiro == "C" ~ 3, # 3 or more
          .default          = NA,
        ),
        
        #Bedrooms
        n_quartos = NA,
        
        #Cars
        n_carros = case_when(
          n_carros == "A" ~ 1,
          n_carros == "B" ~ 2,
          n_carros == "C" ~ 3,
          n_carros == "D" ~ 0,
          .default        = NA
        ),
        
        #Refrigerators
        n_geladeira = case_when(
          n_geladeira == "A" ~ 1,
          n_geladeira == "B" ~ 2,
          n_geladeira == "C" ~ 3,
          n_geladeira == "D" ~ 0,
          .default           = NA
        ),
        
        #Cell phones
        n_celular = case_when(
          n_celular == "A" ~ 1,
          n_celular == "B" ~ 2,
          n_celular == "C" ~ 3,
          n_celular == "D" ~ 0,
          .default         = NA
        ),
        
        #PC
        pc = case_when(
          pc == "A" ~ 1,
          pc == "B" ~ 2,
          pc == "C" ~ 3,
          pc == "D" ~ 0,
          .default  = NA
        ),
        
        internet = case_when(
          internet == "D" ~ 0,
          internet %in% c("A", "B", "C") ~ 1,
          .default      = NA
        )
      )
    } else if (ano %in% c(2015:2019)) { #Years 2015-2019
    
    base <- base %>% 
      mutate(
        #Domestic worker
        empr_dom = case_when(
          empr_dom == "A" ~ 0, #No domestic worker
          empr_dom %in% c("B", "C", "D") ~ 1,
          .default        = NA  #With one or more
        ),
        
        #Bathrooms
        n_banheiro = case_when(
          n_banheiro == "A" ~ 0,
          n_banheiro == "B" ~ 1,
          n_banheiro == "C" ~ 2,
          n_banheiro == "D" ~ 3, 
          n_banheiro == "E" ~ 4, #4 or more
          .default          = NA
        ),
        
        #Bedrooms
        n_quartos = case_when(
          n_quartos == "A" ~ 0,
          n_quartos == "B" ~ 1,
          n_quartos == "C" ~ 2,
          n_quartos == "D" ~ 3, 
          n_quartos == "E" ~ 4, #4 or more
          .default         = NA
        ),
        
        #Cars
        n_carros = case_when(
          n_carros == "A" ~ 0,
          n_carros == "B" ~ 1,
          n_carros == "C" ~ 2,
          n_carros == "D" ~ 3, 
          n_carros == "E" ~ 4, #4 or more
          .default        = NA
        ),
        
        #Refrigerators
        n_geladeira = case_when(
          n_geladeira == "A" ~ 0,
          n_geladeira == "B" ~ 1,
          n_geladeira == "C" ~ 2,
          n_geladeira == "D" ~ 3, 
          n_geladeira == "E" ~ 4, #4 or more
          .default           = NA
        ),
        
        #Cell phones
        n_celular = case_when(
          n_celular == "A" ~ 0,
          n_celular == "B" ~ 1,
          n_celular == "C" ~ 2,
          n_celular == "D" ~ 3, 
          n_celular == "E" ~ 4, #4 or more
          .default         = NA
        ),
        
        #PC
        pc = case_when(
          pc == "A" ~ 0,
          pc == "B" ~ 1,
          pc == "C" ~ 2,
          pc == "D" ~ 3, 
          pc == "E" ~ 4, #4 or more
          .default  = NA
        ),
        
        internet = case_when(
          internet == "B" ~ 0,
          internet == "A" ~ 1,
          .default        = NA
        )
      )
    
  }
  
  # Essay absence ------------------------------------------------------#
  # Creates the essay absence flag. Older years use status codes directly, while
  # newer years infer absence from exam-day presence variables.
  
  if (ano %in% c(2009,2011)) {
    
    # Modifications only for 2009
    base <- base %>%
      mutate(
        abs_rd = case_when(
          status_rd == "B" ~ 0,
          # Submitted blank essay
          status_rd == "F" ~ 1,
          # Missed the exam
          status_rd == "N" ~ 0,
          # Essay annulled
          status_rd == "P" ~ 0,
          # Present for the exam
          .default = NA
        )
      )
  } else if (ano == 2010) {
    
    # Modifications only for 2010
    base <- base %>%
      mutate(
        abs_rd = case_when(
          status_rd == "B" ~ 0,
          # Submitted blank essay
          status_rd == "D" ~ 0,
          # Disregarded
          status_rd == "F" ~ 1,
          # Missed the exam
          status_rd == "N" ~ 0,
          # Essay annulled
          status_rd == "P" ~ 0,
          # Present for the exam
          .default = NA
        )
      )
  } else if (ano == 2012) {
    
    # Modifications only for 2012
    base <- base %>%
      mutate(
        abs_rd = case_when(
          status_rd == "B" ~ 0,
          # Submitted blank essay
          status_rd == "F" ~ 1,
          # Missed the exam
          status_rd == "N" ~ 0,
          # Essay annulled
          status_rd == "P" ~ 0,
          # Present for the exam
          status_rd == "T" ~ 0,
          # Off topic
          status_rd == "I" ~ 0,
          # Insufficient text
          status_rd == "A" ~ 0,
          # Does not meet the text type
          status_rd == "H" ~ 0,
          # Annulled - violates human rights
          status_rd == "C" ~ 0,
          # Copied prompt text
          .default = NA
        )
      )
    
  } else if (ano == 2013) {
    
    # Modifications only for 2013 
    base <- base %>%
      mutate(
        # Does not have option 8
        abs_rd = case_when(
          status_rd == 1 ~ 0,
          # Submitted blank essay
          status_rd == 6 ~ 1,
          # Missed the exam
          status_rd == 2 ~ 0,
          # Essay annulled
          status_rd == 7 ~ 0,
          # Present for the exam
          status_rd == 3 ~ 0,
          # Off topic
          status_rd == 5 ~ 0,
          # Insufficient text
          status_rd == 4 ~ 0,
          # Does not meet the text type
          status_rd == 9 ~ 0,
          # Annulled - violates human rights
          status_rd == 10 ~ 0,
          # Copied prompt text
          .default = NA
        )
      )
    
  } else if (ano == 2014) {
    
    # Modifications only for 2014 
    base <- base %>%
      mutate(
        # Does not have option 8
        abs_rd = case_when(
          status_rd == 1 ~ 0,
          # Submitted blank essay
          status_rd == 6 ~ 1,
          # Missed the exam
          status_rd == 2 ~ 0,
          # Essay annulled
          status_rd == 1 ~ 0,
          # Present for the exam
          status_rd == 3 ~ 0,
          # Off topic
          status_rd == 5 ~ 0,
          # Insufficient text
          status_rd == 4 ~ 0,
          # Does not meet the text type
          status_rd == 9 ~ 0,
          # Annulled - violates human rights
          status_rd == 10 ~ 0,
          # Copied prompt text
          status_rd == 11 ~ 0,
          # Part of the text disconnected from the proposed theme
          .default = NA
        )
      )
    
  } else if (ano == 2015) {
    
    # Modifications only for 2015 
    # base <- base %>%
    #   mutate(
    #     # No absence option available
    #     abs_rd = case_when(
    #       status_rd == 4 ~ 0,
    #       # Submitted blank essay
    #       status_rd == 2 ~ 0,
    #       # Essay annulled
    #       status_rd == 1 ~ 0,
    #       # Present for the exam
    #       status_rd == 6 ~ 0,
    #       # Off topic
    #       status_rd == 8 ~ 0,
    #       # Insufficient text
    #       status_rd == 7 ~ 0,
    #       # Does not meet the text type
    #       status_rd == 5 ~ 0,
    #       # Annulled - violates human rights
    #       status_rd == 3 ~ 0,
    #       # Copied prompt text
    #       status_rd == 9 ~ 0,
    #       # Part of the text disconnected from the proposed theme
    #       status_rd == 98 ~ 0,
    #       # Does not meet notice item 2.2.5: provide supporting documents for the condition that motivates the specialized and/or specific service request.
    #       .default = 1
    #     )
    #   )
    
    # No absence option available
    base <- base %>%
      mutate(
        abs_rd = ifelse(pres_lc == 0 & pres_mt == 0, 1, 0)
      )
    
  } else if (ano == 2016) {
    
    # # Modifications only for 2016 
    # base <- base %>%
    #   mutate(
    #     # No absence option available
    #     abs_rd = case_when(
    #       status_rd == 4 ~ 0,
    #       # Submitted blank essay
    #       status_rd == 2 ~ 0,
    #       # Essay annulled
    #       status_rd == 1 ~ 0,
    #       # Present for the exam
    #       status_rd == 6 ~ 0,
    #       # Off topic
    #       status_rd == 8 ~ 0,
    #       # Insufficient text
    #       status_rd == 7 ~ 0,
    #       # Does not meet the text type
    #       status_rd == 5 ~ 0,
    #       # Annulled - violates human rights
    #       status_rd == 3 ~ 0,
    #       # Copied prompt text
    #       status_rd == 9 ~ 0,
    #       # Part of the text disconnected from the proposed theme
    #       .default = 1
    #     )
    #   )
    
    # No absence option available
    base <- base %>%
      mutate(
        abs_rd = ifelse(pres_lc == 0 & pres_mt == 0, 1, 0)
      )
    
  } else if(ano %in% c(2017, 2018, 2019)) {
    
    # # Modifications only for 2017 to 2019 
    # base <- base %>%
    #   mutate(
    #     
    #     # 2017, 2018, 2019 - does not have option 5 or an absence option
    #     abs_rd = case_when(
    #       status_rd == 4 ~ 0,                      # Submitted blank essay
    #       status_rd == 2 ~ 0,                      # Essay annulled
    #       status_rd == 1 ~ 0,                      # Present for the exam
    #       status_rd == 6 ~ 0,                      # Off topic
    #       status_rd == 8 ~ 0,                      # Insufficient text
    #       status_rd == 7 ~ 0,                      # Does not meet the text type
    #       status_rd == 3 ~ 0,                     # Copied prompt text
    #       status_rd == 9 ~ 0,                     # Part of the text disconnected from the proposed theme
    #       .default = 1
    #     )
    #     
    #   )
    
    # No absence option available
    base <- base %>%
      mutate(
        abs_rd = ifelse(pres_lc == 0 & pres_ch == 0, 1, 0)
      )
  }
  
  
  # Absence in objective tests --------------------------------------------#
  # Creates absence indicators for each objective test area.
  
  # All years    
  base <- base %>%
    mutate(
      
      abs_cn = case_when(
        pres_cn == 0 ~ 1,                          # Missed the exam
        pres_cn == 1 ~ 0,                          # Present for the test
        pres_cn == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      ),
      abs_ch = case_when(
        pres_ch == 0 ~ 1,                          # Missed the exam
        pres_ch == 1 ~ 0,                          # Present for the test
        pres_ch == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      ),
      abs_lc = case_when(
        pres_lc == 0 ~ 1,                          # Missed the exam
        pres_lc == 1 ~ 0,                          # Present for the test
        pres_lc == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      ),
      abs_mt = case_when(
        pres_mt == 0 ~ 1,                          # Missed the exam
        pres_mt == 1 ~ 0,                          # Present for the test
        pres_mt == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      )
      
    )
  
  # Sex ----------------------------------------------------------------------#
  # Standardizes sex into the `mas` indicator used later in the pipeline.
  if(ano <= 2010 | ano >= 2013){
    
    base <- base %>%
      mutate(
        mas = ifelse(sexo == "M", 0, 1)
      )
    
  } else if (ano %in% c(2011,2012)) {
    
    base <- base %>%
      mutate(
        mas = sexo
      )
  }
  
  
  
  
  # Filters and new variables -------------------------------------------------#
  
  # General filter
  # Adds common school, geography, average-score, and year variables.
  base <- base %>%
    filter(
      #conclusao == 2,
      #idade > 18
    ) %>%
    mutate(hv = ifelse(mun_prova %/% 100000 > 30, 1, 0)) %>%
    mutate(
      urb = ifelse(urb_rur == 1, 1, 0),
      priv = ifelse(dep_adm == 4, 1, 0),
      media = (cn + ch + lc + mt + rd) / 5,
      ano = ano
    ) %>%
    relocate(media, .after = rd) %>%
    relocate(ano, .before = idade) %>%
    relocate(mun_escola, .after = mun_prova)
  
  return(base)
  
}


filtros <- function(base,filtro) {
  
  # Filter for score-regression dataset - no missing or invalid values
  # Keeps observations with valid scores and key school identifiers for score
  # regressions.
  if (filtro == "notas") {
    
    base <- base %>%
      filter(
        !is.na(cn) &
          !is.na(ch) &
          !is.na(lc) &
          !is.na(mt) &
          !is.na(rd) &   
          !is.na(dep_adm) &
          # !is.na(urb_rur) &
          # !is.na(sexo) &
          # !is.na(raca) &
          # !is.na(pessoas_dom) &
          # !is.na(renda_dom) &
          # !is.na(esc_pai) &
          # esc_pai != "H" &
          # raca != "G" &
          # renda_dom != "E" &
          # pessoas_dom != "D" &
          !is.na(mun_escola) &!is.na(func_esc)
      )
    
  } else if(filtro == "abs") {
    
    # Filter for absence-regression dataset
    # Removes score-only variables when the output will be used for absences.
    if("treineiro" %in% colnames(enem)){
      
      base_a <- base %>%
        select(-c(cn,ch,lc,mt,rd,sexo,raca,pessoas_dom,renda_dom,
                  esc_pai,mun_escola,func_esc,rd1,rd2,rd3,rd4,rd5,co_cn,co_ch,co_lc,
                  co_mt,pres_cn,pres_ch,pres_lc,pres_mt,status_rd,treineiro))
      
    } else {
      
      base_a <- base %>%
        select(-c(cn,ch,lc,mt,rd,sexo,raca,pessoas_dom,renda_dom,
                  esc_pai,mun_escola,func_esc,rd1,rd2,rd3,rd4,rd5,co_cn,co_ch,co_lc,
                  co_mt,pres_cn,pres_ch,pres_lc,pres_mt,status_rd))
      
    }
    
    
  }
  
  return(base)
  
}

