## 3.3 Joined data ----
# ---------------------------------------------------------------------------- #

# Combines scores, item-level outcomes, geography, and GDP into the final
# no-age-filter base for each ENEM year.

# GDP
pib <- readRDS(file = file.path(revision_path, "pib.RDS")) %>%
  mutate(codmun = as.integer(codmun)) %>%
  rename(mun_prova = codmun)

# Distance base
mun_hv <- readRDS(file = file.path(revision_path, "mun_hv.RDS"))

# Coordinates
coordenadas <- mun_hv$centroid %>%
  st_coordinates() %>%
  as_tibble() %>%
  rename(
    lon = X,
    lat = Y
  )

mun_hv <- mun_hv %>%
  bind_cols(coordenadas) %>%
  st_drop_geometry() %>%
  select(co_municipio, lon, lat, dist_hv_border, seg)
rm(coordenadas)

# Datasets for all years
# Loops through each standardized ENEM year and creates the analysis variables.
for(ano in 2013:2019){
  
  ini <- Sys.time()
  message("Starting for: ", ano)
  
  temp <- readRDS(file = path_paste(no_age_path, "enem_notas_",ano,"_v4.RDS")) %>%
    filtros(filtro = "notas")
  # Loads item outcomes and pivots them to one row per student.
  temp2 <- readRDS(file = path_paste(no_age_path, "enem_ace_",ano,"_v4.RDS"))%>%
    mutate(
      sg_area = tolower(sg_area)
    ) %>%
    dcast(id_enem ~ sg_area,
          value.var = c(
            "acerto",
            paste0(
              "acerto_",
              rep(c("a","b","c"), each = 2), rep(c("l","h"), times = 3)
            ),
            paste0(
              "acerto_",
              rep(c("ini","fim"), each = 2), rep(c("5","10"), times = 2)
            ),
            "branco","dupla"
          )
    )
  
  temp <- temp %>% merge(temp2, by = "id_enem", all.y = F,all.x = F)
  rm(temp2)
  
  
  
  message("Creating the variables")
  # Adds signed HV distance, exam-day score averages, demographic indicators,
  # migration-school indicators, and item-performance measures.
  temp <- temp %>%
    select(-sexo,-status_rd) %>%
