# Same helper structure as Section 2, reused for the all-observations pipeline.
pad <- function(x){
  x = (x - mean(x, na.rm = T)) / 
    sd(x, na.rm = T)
  return(x)
}

# Function to calculate the weighted standard errors, according to formula on:
#https://medium.com/@OttoYu/weighted-mean-and-standard-devation-computation-f1dbacdf49b6

weighted.sd <- function(x,w,na.rm){
  
  # Verifying whether x and w have the same length
  if(length(x) == length(w)){
    
    # removing NA
    if(!missing(na.rm)){
      if(na.rm == T){
        temp <- !is.na(x) & !is.na(w)
        x <- x[temp]
        w <- w[temp]
        rm(temp)
      } 
    }
    
    # Calculating SD
    x = ((w %*% (x - weighted.mean(x, w = w))^2) / (sum(w)))^(1/2)
    
    return(x)
  }
}

wpad <- function(x,w){
  x = (x - weighted.mean(x,w = w, na.rm = T))/as.vector(weighted.sd(x, w = w, na.rm = T))
  return(x)
}



org_data <- function(base,ano,vlist,cnames) {
  
  # Data organization
  # Reorders columns and applies the common names for the broader sample.
  base <- base %>% relocate(vlist)
  
  colnames(base) <- cnames
  
  # People in the household ------------------------------------------------------#
  # Harmonizes household-size categories across ENEM questionnaires.
  
  if (ano == 2009) {
    # Modifications only for 2009
    
    base <- base %>%
      mutate(
        # 2009
        pessoas_dom = case_when(
          pessoas_dom == 'F' ~ 'A',
          # 1 person
          pessoas_dom %in% c('A', 'B', 'C') ~ 'B',
          # 2 to 4 people
          pessoas_dom %in% c('D', 'E') ~ 'C',
          # 5 or more people
          .default = 'D'
        ),
      )
  } else if (ano == 2010) {
    # Modifications only for 2010
    
    base <- base %>%
      mutate(
        # 2010
        pessoas_dom = case_when(
          pessoas_dom == 'E' ~ 'A',
          pessoas_dom == 'A' ~ 'B',
          pessoas_dom %in% c('B', 'C', 'D') ~ 'C',
          .default = 'D'
        )
      )
    
  } else if (ano == 2011) {
    
    # Modifications only for 2011
    base <- base %>%
      mutate(
        pessoas_dom = as.integer(pessoas_dom),
        pessoas_dom = case_when(
          pessoas_dom == 1 ~ 'A',
          pessoas_dom >= 2 & pessoas_dom <= 4 ~ 'B',
          pessoas_dom >= 5 & pessoas_dom <= 20 ~ 'C',
          .default = 'D'
        )
      )
    
  } else if (ano >= 2012) {
    
    # Modifications only for 2012 to 2019
    base <- base %>%
      mutate(
        npessoas_dom = as.numeric(pessoas_dom),
        pessoas_dom = case_when(
          pessoas_dom == 1 ~ 'A',
          pessoas_dom >= 2 & pessoas_dom <= 4 ~ 'B',
          pessoas_dom >= 5 & pessoas_dom <= 20 ~ 'C',
          .default = 'D'
        )
      )
  }  
  
  # Household income ----------------------------------------------------------#
  # Harmonizes household-income categories across ENEM questionnaires.
  
  if (ano %in% c(2009,2010)) {
    
    # Modifications only for 2009 and 2010
    base <- base %>%
      mutate(
        # 2009, 2010
        renda_dom = case_when(
          renda_dom == 'H' ~ 'A',
          # None
          renda_dom == 'A' ~ 'B',
          # Up to 1 MW
          renda_dom %in% c('B', 'C', 'D') ~ 'C',
          # >1 to 10 MW
          renda_dom %in% c('E', 'F', 'G') ~ 'D',
          # >10 to 50 MW
          .default = 'E'
        )
      )
  } else if (ano == 2011) {
    
    # Modifications only for 2011
    base <- base %>%
      mutate(
        renda_dom = case_when(
          renda_dom == 'A' ~ 'A',
          renda_dom == 'B' ~ 'B',
          renda_dom %in% c('C', 'D', 'E', 'F', 'G') ~ 'C',
          renda_dom %in% c('H', 'I', 'J', 'K') ~ 'D',
          .default = 'E'
        )
      )
  } else if (ano >= 2012) {
    
    # Modifications from 2012 onward
    base <- base %>%
      mutate(
        renda_dom = case_when(
          renda_dom == 'A' ~ 'A',
          renda_dom == 'B' ~ 'B',
          renda_dom %in% c('C', 'D', 'E', 'F', 'G', 'H', 'I', 'J', 'K', 'L', 'M') ~ 'C',
          renda_dom %in% c('N', 'O', 'P', 'Q') ~ 'D',
          .default = 'E'
        )
      )
  }
  
  # Race ----------------------------------------------------------------------#
  # Harmonizes race/color categories and invalid/missing responses.
  
  if(ano == 2009) {
    
    # Modifications only for 2009
    base <- base %>%
      mutate(
        # 2009
        raca = case_when(
          raca %in% c('', '*', '.') ~ 'A',
          # invalid
          raca == 'A' ~ 'B',
          # white
          raca == 'C' ~ 'C',
          # black
          raca == 'B' ~ 'D',
          # brown/mixed
          raca == 'D' ~ 'E',
          # yellow/Asian
          raca == 'E' ~ 'F',
          # indigenous
          .default = 'G'
        )
      )
  } else if (ano %in% c(2010, 2011, 2012, 2013, 2014, 2017, 2018, 2019)) {
    
    # Modifications only for 2010 to 2014 and 2017 to 2019
    base <- base %>%
      mutate(
        # 2010, 2011, 2012, 2013, 2014, 2017, 2018, 2019
        raca = case_when(
          raca == 0 ~ 'A',
          raca == 1 ~ 'B',
          raca == 2 ~ 'C',
          raca == 3 ~ 'D',
          raca == 4 ~ 'E',
          raca == 5 ~ 'F',
          .default = 'G'
        )
        
      )
    
  } else if(ano %in% c(2015,2016)) {
    
    # Modifications only for 2015 and 2016
    base <- base %>%
      mutate(
        
        # 2015, 2016
        raca = case_when(
          raca %in% c(0,6) ~ 'A',
          raca == 1 ~ 'B',
          raca == 2 ~ 'C',
          raca == 3 ~ 'D',
          raca == 4 ~ 'E',
          raca == 5 ~ 'F',
          .default = 'G')
        
      )
    
  }
  
  # Father's education -------------------------------------------------------#
  # Harmonizes parental education categories across years.
  
  if (ano == 2010) {
    
    # Modifications only for 2010
    base <- base %>%
      mutate(
        esc_pai = case_when(
          esc_pai == "H" ~ "A",
          esc_pai == "A" ~ "B",
          esc_pai == "B" ~ "C",
          esc_pai == "C" ~ "D",
          esc_pai == "D" ~ "E",
          esc_pai %in% c("E", "F", "G") ~ "F",
          esc_pai == "I" ~ "G",
          .default = "H"
        ),
        
        esc_mae = case_when(
          esc_mae == "H" ~ "A",
          esc_mae == "A" ~ "B",
          esc_mae == "B" ~ "C",
          esc_mae == "C" ~ "D",
          esc_mae == "D" ~ "E",
          esc_mae %in% c("E", "F", "G") ~ "F",
          esc_mae == "I" ~ "G",
          .default = "H"
        )
      )
  } else if (ano == 2009 | (ano >= 2009 & ano <= 2014)) {
    
    # Modifications only for 2009 and 2011 to 2014
    base <- base %>%
      mutate(
