          # Higher education complete
          esc_mae == "H" ~ "F",
          # Postgraduate
          esc_mae == "I" ~ "G",
          # Does not know
          .default = "H"
          # missing
        )
        
      )
  } else if (ano >= 2015 & ano <= 2019) {
    
    # Modifications only for 2015 to 2019
    base <- base %>%
      mutate(
        esc_pai = case_when(
          esc_pai %in% c("A", "B") ~ "A",
          esc_pai == "C" ~ "B",
          esc_pai == "D" ~ "C",
          esc_pai == "E" ~ "D",
          esc_pai == "F" ~ "E",
          esc_pai == "G" ~ "F",
          esc_pai == "H" ~ "G",
          .default = "H"
        ),
        esc_mae = case_when(
          esc_mae %in% c("A", "B") ~ "A",
          esc_mae == "C" ~ "B",
          esc_mae == "D" ~ "C",
          esc_mae == "E" ~ "D",
          esc_mae == "F" ~ "E",
          esc_mae == "G" ~ "F",
          esc_mae == "H" ~ "G",
          .default = "H"
        ) 
        
        
        
      )
  } 
  
  # Essay absence ------------------------------------------------------#
  # Creates the essay absence flag using the available year-specific coding.
  
  if (ano %in% c(2009,2011)) {
    
    # Modifications only for 2009
    base <- base %>%
      mutate(
        abs_rd = case_when(
          status_rd == "B" ~ 0,
          # Submitted blank essay
          status_rd == "F" ~ 1,
          # Missed the exam
          status_rd == "N" ~ 0,
          # Essay annulled
          status_rd == "P" ~ 0,
          # Present for the exam
          .default = NA
        )
      )
  } else if (ano == 2010) {
    
    # Modifications only for 2010
    base <- base %>%
      mutate(
        abs_rd = case_when(
          status_rd == "B" ~ 0,
          # Submitted blank essay
          status_rd == "D" ~ 0,
          # Disregarded
          status_rd == "F" ~ 1,
          # Missed the exam
          status_rd == "N" ~ 0,
          # Essay annulled
          status_rd == "P" ~ 0,
          # Present for the exam
          .default = NA
        )
      )
  } else if (ano == 2012) {
    
    # Modifications only for 2012
    base <- base %>%
      mutate(
        abs_rd = case_when(
          status_rd == "B" ~ 0,
          # Submitted blank essay
          status_rd == "F" ~ 1,
          # Missed the exam
          status_rd == "N" ~ 0,
          # Essay annulled
          status_rd == "P" ~ 0,
          # Present for the exam
          status_rd == "T" ~ 0,
          # Off topic
          status_rd == "I" ~ 0,
          # Insufficient text
          status_rd == "A" ~ 0,
          # Does not meet the text type
          status_rd == "H" ~ 0,
          # Annulled - violates human rights
          status_rd == "C" ~ 0,
          # Copied prompt text
          .default = NA
        )
      )
    
  } else if (ano == 2013) {
    
    # Modifications only for 2013 
    base <- base %>%
      mutate(
        # Does not have option 8
        abs_rd = case_when(
          status_rd == 1 ~ 0,
          # Submitted blank essay
          status_rd == 6 ~ 1,
          # Missed the exam
          status_rd == 2 ~ 0,
          # Essay annulled
          status_rd == 7 ~ 0,
          # Present for the exam
          status_rd == 3 ~ 0,
          # Off topic
          status_rd == 5 ~ 0,
          # Insufficient text
          status_rd == 4 ~ 0,
          # Does not meet the text type
          status_rd == 9 ~ 0,
          # Annulled - violates human rights
          status_rd == 10 ~ 0,
          # Copied prompt text
          .default = NA
        )
      )
    
  } else if (ano == 2014) {
    
    # Modifications only for 2014 
    base <- base %>%
      mutate(
        # Does not have option 8
        abs_rd = case_when(
          status_rd == 1 ~ 0,
          # Submitted blank essay
          status_rd == 6 ~ 1,
          # Missed the exam
          status_rd == 2 ~ 0,
          # Essay annulled
          status_rd == 1 ~ 0,
          # Present for the exam
          status_rd == 3 ~ 0,
          # Off topic
          status_rd == 5 ~ 0,
          # Insufficient text
          status_rd == 4 ~ 0,
          # Does not meet the text type
          status_rd == 9 ~ 0,
          # Annulled - violates human rights
          status_rd == 10 ~ 0,
          # Copied prompt text
          status_rd == 11 ~ 0,
          # Part of the text disconnected from the proposed theme
          .default = NA
        )
      )
    
  } else if (ano == 2015) {
    
    # Modifications only for 2015 
    # base <- base %>%
    #   mutate(
    #     # No absence option available
    #     abs_rd = case_when(
    #       status_rd == 4 ~ 0,
    #       # Submitted blank essay
    #       status_rd == 2 ~ 0,
    #       # Essay annulled
    #       status_rd == 1 ~ 0,
    #       # Present for the exam
    #       status_rd == 6 ~ 0,
    #       # Off topic
    #       status_rd == 8 ~ 0,
    #       # Insufficient text
    #       status_rd == 7 ~ 0,
    #       # Does not meet the text type
    #       status_rd == 5 ~ 0,
    #       # Annulled - violates human rights
    #       status_rd == 3 ~ 0,
    #       # Copied prompt text
    #       status_rd == 9 ~ 0,
    #       # Part of the text disconnected from the proposed theme
    #       status_rd == 98 ~ 0,
    #       # Does not meet notice item 2.2.5: provide supporting documents for the condition that motivates the specialized and/or specific service request.
    #       .default = 1
    #     )
    #   )
    
    # No absence option available
    base <- base %>%
      mutate(
        abs_rd = ifelse(pres_lc == 0 & pres_mt == 0, 1, 0)
      )
    
  } else if (ano == 2016) {
    
    # # Modifications only for 2016 
    # base <- base %>%
    #   mutate(
    #     # No absence option available
    #     abs_rd = case_when(
    #       status_rd == 4 ~ 0,
    #       # Submitted blank essay
    #       status_rd == 2 ~ 0,
    #       # Essay annulled
    #       status_rd == 1 ~ 0,
    #       # Present for the exam
    #       status_rd == 6 ~ 0,
    #       # Off topic
    #       status_rd == 8 ~ 0,
    #       # Insufficient text
    #       status_rd == 7 ~ 0,
    #       # Does not meet the text type
    #       status_rd == 5 ~ 0,
    #       # Annulled - violates human rights
    #       status_rd == 3 ~ 0,
    #       # Copied prompt text
    #       status_rd == 9 ~ 0,
    #       # Part of the text disconnected from the proposed theme
    #       .default = 1
    #     )
    #   )
    
    # No absence option available
    base <- base %>%
      mutate(
        abs_rd = ifelse(pres_lc == 0 & pres_mt == 0, 1, 0)
      )
    
  } else if(ano %in% c(2017, 2018, 2019)) {
    
    # # Modifications only for 2017 to 2019 
    # base <- base %>%
    #   mutate(
    #     
    #     # 2017, 2018, 2019 - does not have option 5 or an absence option
    #     abs_rd = case_when(
    #       status_rd == 4 ~ 0,                      # Submitted blank essay
    #       status_rd == 2 ~ 0,                      # Essay annulled
    #       status_rd == 1 ~ 0,                      # Present for the exam
    #       status_rd == 6 ~ 0,                      # Off topic
    #       status_rd == 8 ~ 0,                      # Insufficient text
    #       status_rd == 7 ~ 0,                      # Does not meet the text type
    #       status_rd == 3 ~ 0,                     # Copied prompt text
    #       status_rd == 9 ~ 0,                     # Part of the text disconnected from the proposed theme
    #       .default = 1
    #     )
    #     
    #   )
    
    # No absence option available
    base <- base %>%
      mutate(
        abs_rd = ifelse(pres_lc == 0 & pres_ch == 0, 1, 0)
      )
  }
  
  
  # Absence in objective tests --------------------------------------------#
  # Creates absence indicators for each objective test.
  
  # All years    
  base <- base %>%
    mutate(
      
      abs_cn = case_when(
        pres_cn == 0 ~ 1,                          # Missed the exam
        pres_cn == 1 ~ 0,                          # Present for the test
        pres_cn == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      ),
      abs_ch = case_when(
        pres_ch == 0 ~ 1,                          # Missed the exam
        pres_ch == 1 ~ 0,                          # Present for the test
        pres_ch == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      ),
      abs_lc = case_when(
        pres_lc == 0 ~ 1,                          # Missed the exam
        pres_lc == 1 ~ 0,                          # Present for the test
        pres_lc == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      ),
      abs_mt = case_when(
        pres_mt == 0 ~ 1,                          # Missed the exam
        pres_mt == 1 ~ 0,                          # Present for the test
        pres_mt == 2 ~ 0,                          # Eliminated from the test
        .default = NA
      )
      
    )
  
  # Sex ----------------------------------------------------------------------#
  # Standardizes sex into the indicator used later in the sample construction.
  if(ano <= 2010 | ano >= 2013){
    
    base <- base %>%
      mutate(
        mas = ifelse(sexo == "M", 0, 1)
      )
    
  } else if (ano %in% c(2011,2012)) {
    
    base <- base %>%
      mutate(
        mas = sexo
      )
  }
  
  
  
  
  # Filters and new variables -------------------------------------------------#
  
  # General filter
  # Adds common geography, school, score, and year variables, then keeps the
  # non-graduating applicant universe. The type-specific split is applied below.
  base <- base %>%
    
    mutate(hv = ifelse(mun_prova %/% 100000 > 30, 1, 0)) %>%
    mutate(
      urb = ifelse(urb_rur == 1, 1, 0),
      priv = ifelse(dep_adm == 4, 1, 0),
      media = (cn + ch + lc + mt + rd) / 5,
      ano = ano
    ) %>%
    relocate(media, .after = rd) %>%
    relocate(ano, .before = idade) %>%
    relocate(mun_escola, .after = mun_prova) %>% 
    filter(conclusao != 2)
  
  return(base)
  
}


filtros <- function(base,filtro) {
  
  # Filter for score-regression dataset - no missing or invalid values
  # Keeps complete observations for score regressions in the broader sample.
  if (filtro == "notas") {
    
    base <- base %>%
      filter(
        !is.na(cn) &
          !is.na(ch) &
          !is.na(lc) &
          !is.na(mt) &
          !is.na(rd) &   
          #!is.na(dep_adm) &
          #!is.na(urb_rur) &
          !is.na(sexo) &
          !is.na(raca) &
          !is.na(pessoas_dom) &
          !is.na(renda_dom) &
          !is.na(esc_pai) &
          esc_pai != "H" &
          raca != "G" &
          renda_dom != "E" &
          pessoas_dom != "D" #&
        #!is.na(mun_escola) &
        #!is.na(func_esc)
      )
    
  } else if(filtro == "abs") {
    
    # Filter for absence-regression dataset
    # Removes score-only variables when saving the absence file.
    if("treineiro" %in% colnames(enem)){
      
      base_a <- base %>%
        select(-c(cn,ch,lc,mt,rd,sexo,raca,pessoas_dom,renda_dom,
                  esc_pai,mun_escola,func_esc,rd1,rd2,rd3,rd4,rd5,co_cn,co_ch,co_lc,
                  co_mt,pres_cn,pres_ch,pres_lc,pres_mt,status_rd,treineiro))
      
    } else {
      
      base_a <- base %>%
        select(-c(cn,ch,lc,mt,rd,sexo,raca,pessoas_dom,renda_dom,
                  esc_pai,mun_escola,func_esc,rd1,rd2,rd3,rd4,rd5,co_cn,co_ch,co_lc,
                  co_mt,pres_cn,pres_ch,pres_lc,pres_mt,status_rd))
      
    }
    
    
  }
  
  return(base)
  
}

