# Reads all item-parameter files and prepares the thresholds used in the item
# outcome pipeline.
# Loop over test years
for (ano in 2009:2019) {
  
  temp <-
    fread(
      path_paste(enem_parameters_path, "itens_prova_", ano, ".csv")
    ) %>% 
    rename_all(tolower) %>%
    mutate(ano = ano) %>%
    filter(in_item_aban == 0) %>%
    select(-in_item_aban, -tx_motivo_aban)
  
  
  if(ano == 2009) {
    itens_prova <- temp
  } else {
    itens_prova <- itens_prova %>% bind_rows(temp)
  }
  
  rm(temp)
  rm(ano)
}

itens_prova <- itens_prova %>%
  # Renumbers item positions within each subject/test form and drops foreign-language
  # alternatives from the common item pool.
  group_by(sg_area, co_prova) %>%
  mutate(
    pos_min = min(co_posicao),
    co_posicao = co_posicao - pos_min + 1
  ) %>%
  ungroup() %>%
  filter(is.na(tp_lingua)) %>%
  select(-pos_min,-tp_lingua,in_item_adaptado)


setDT(itens_prova)
# Computes item-parameter medians used to classify items as below/above parameter
# thresholds.
medians <-
  itens_prova[, .(
    a_md = median(nu_param_a, na.rm = T),
    b_md = median(nu_param_b, na.rm = T),
    c_md = median(nu_param_c, na.rm = T)
  ), by = .(sg_area, ano, co_prova)]

# Stores average item parameters by subject/year for checks.
itens_medias <-
  itens_prova[, .(
    a_md = mean(nu_param_a, na.rm = T),
    b_md = mean(nu_param_b, na.rm = T),
    c_md = mean(nu_param_c, na.rm = T)
  ), by = .(sg_area, ano)]

