# Raw ENEM files used by the all-observations pipeline.
flist <- c(
  enem_raw_file(2018, "MICRODADOS_ENEM_2018.csv"),
  enem_raw_file(2019, "MICRODADOS_ENEM_2019.csv")
)

# Runs the same all-observations pipeline for each non-graduating applicant type.
for(type in c("mock", "older")) {
  
  if(type == "mock") {
    
    # Keeps mock applicants/trainees.
    filter_type <- function(base) {
      base <- base %>% 
        filter(treineiro == 1)
    }
    
  } else if(type == "older") {
    
    # Keeps older non-graduating applicants and removes trainees.
    filter_type <- function(base) {
      base <- base %>% 
        filter(
          conclusao != 2,
          treineiro != 1
        )
    }
    
  }
  
# Reads, harmonizes, filters, and saves the 2018-2019 score/absence datasets.
for(i in 2018:2019){
  
  print(paste0("Ano: ",i))
  ini <- Sys.time()
  
  j <- i - 2017
  delta <- ifelse(i <= 2014,1,0)
  # Selects the raw variable list and common output names for the current year.
  vlist <- vlist_df[1:(nrow(vlist_df) - delta),j]
  cnames <- vlist_df[1:(nrow(vlist_df) - delta),ncol(vlist_df)]
  rm(delta)
  
  if (i <= 2010 | i >= 2016){
    
    enem <-
      fread(file = flist[j],
            sep = ";",
            select = vlist)
    
  } else if(i >= 2011 & i <= 2015){
    enem <- read_dta(file = flist[j], col_select = vlist)
  }
  
  print(summary(enem$conclusao))
  
  enem <-
    org_data(
      base = enem,
      ano = i,
      vlist = vlist,
      cnames = cnames
    )
  
  enem <- enem %>% 
    filter_type()
  
  print(summary(enem$conclusao))
  
  enem_notas <- filtros(base = enem, filtro = "notas")
  print(summary(enem_notas$conclusao))
  
  enem_abs <- filtros(base = enem, filtro = "abs")
  
  saveRDS(enem_notas, file = path_paste(all_observations_path, "enem_notas_", i, "_", type, ".RDS"))
  saveRDS(enem_abs, file = path_paste(all_observations_path, "enem_abs_", i, "_", type, ".RDS"))
  
  delta_t <- Sys.time() - ini
  print(delta_t)
  rm(enem,i,j,cnames,vlist,enem_notas,enem_abs, ini,delta_t)
}

