# ---------------------------------------------------------------------------- #
# 7. Census Data ----
# ---------------------------------------------------------------------------- #

# Builds municipality-year counts of students from School Census 2018-2019.

# ---------------------------------------------------------------------------- #
## 7.1. Files ----
# ---------------------------------------------------------------------------- #

# Source files for School Census student situation microdata.
censo_educ <- c(
  file.path(censo_path, "ts_censo_basico_situacao_2018.dta"),
  file.path(censo_path, "ts_censo_basico_situacao_2019.dta")
)
# ---------------------------------------------------------------------------- #
## 7.2 Loop ----
# ---------------------------------------------------------------------------- #

# Reads each census year, keeps the relevant states, public dependencies, and high
# school stages, then counts students by municipality.
for (i in c(1:2)) {
  
  gc()
  
  path <- censo_educ[[i]]
  
  df <- read_dta(path)
  message("Opened INEP data for ", 2017+i)
  
  df <- df %>% 
    # Standardizes names and filters to the geographic/schooling scope of the
    # analysis.
    { names(.) <- tolower(names(.)); . } %>% 
    filter(co_uf %in% c(11, 13, 15, 17, 29,
                        32, 31, 51, 52, 53)) %>% 
    filter(tp_dependencia %in% c(1:3)) %>% 
    filter(tp_etapa_ensino %in% c(27,28,32,33,37,38))
  
  df <- df %>% 
    # Aggregates the filtered records to municipality-year student counts.
    group_by(co_municipio) %>% 
    summarise(alunos = n(),
              .groups = "drop") %>% 
    mutate(ano = 2017 + i) %>% 
    select(ano, co_municipio, alunos)
  
  if ( i == 1) {
    df_final <- df
  } else {
    df_final <- bind_rows(df_final, df)
    
    df_final <- df_final %>%
      arrange(co_municipio,ano)
  }
  
  message("Finished the Data creation for ", i + 2017)
  rm(i, df, path) 
}

saveRDS(df_final, file.path(processed_path, "census_students.RDS"))

rm(df_final, censo_educ)
gc()

