# Starts from the prepared no-age-filter ENEM bases and adds the final controls
# used in the analysis.

# Special Amazonas municipalities with a different exam start time assignment.
am_mun_special <- c(
  1300201, 1300607, 1300706, 1301407, 1301506, 1301654, 1301803, 1301951,
  1302306, 1302405, 1303502, 1303908, 1304062
)

# Stacks 2017-2019 ENEM score bases and keeps students who concluded high school.
base <- readRDS(file = path_paste(no_age_path, "base_nota_2019.RDS")) %>%
  bind_rows(readRDS(file = path_paste(no_age_path, "base_nota_2018.RDS"))) %>%
  bind_rows(readRDS(file = path_paste(no_age_path, "base_nota_2017.RDS"))) %>%
  filter(conclusao == 2) %>% 
  setDT()

#Exam start time dummies
# Creates residence-based exam start time indicators.
base <- base %>% 
  mutate(
    aux_res = mun_res %/% 100000,
    aux_pro = mun_prova %/% 100000,
    
    # Exam start time dummies
    h13 = ifelse(
      aux_res %in% c(
        52, 53, 31, 32, 33, 35, 42, 41, 43,
        29, 28, 27, 26, 25, 24, 23, 22, 21, 17, 15, 16
      ),
      1,0
    ),
    
    h12 = ifelse(
      aux_res %in% c(51, 50, 11, 14) |
        (aux_res == 13 & !mun_res %in% am_mun_special),
      1, 0
    ),
    
    h11 = ifelse(
      
      aux_res == 12 |
        mun_res %in% am_mun_special,
      1, 0
    )
  ) %>% 
  setDT()


summary(base %>% select(idade, conclusao, esc_mae))

