# Computes 2018 score deciles and checks gaps between adjacent decile groups.
media_deciles <- base %>%
  filter(ano == 2018) %>% 
  filter(!is.na(media)) %>%
  mutate(decile = ntile(media, 10)) %>%
  group_by(decile) %>%
  summarise(
    min_media = min(media, na.rm = TRUE),
    max_media = max(media, na.rm = TRUE),
    n = n(),
    .groups = "drop"
  )

media_deciles
media_decile_gaps <- media_deciles %>%
  arrange(desc(decile)) %>%
  mutate(
    lower_group = decile,
    upper_group_min = min_media,
    next_lower_group = lead(decile),
    next_lower_group_max = lead(max_media),
    gap = upper_group_min - next_lower_group_max
  ) %>%
  filter(!is.na(next_lower_group))

media_decile_gaps


#
# Prepares the 2018 distribution plot and overlays decile cutoffs.
base_2018 <- base %>%
  filter(ano == 2018, !is.na(media))

grade_cuts <- quantile(
  base_2018$media,
  probs = seq(0, 1, 0.1),
  na.rm = TRUE
)

ggplot(base_2018, aes(x = media)) +
  geom_histogram(
    bins = 60,
    fill = "gray75",
    color = "white"
  ) +
  geom_vline(
    xintercept = grade_cuts,
    linewidth = 0.35,
    linetype = "dashed",
    color = "red"
  ) +
  labs(
    x = "Grade",
    y = "Number of students"
  ) +
  theme_bw()



